229	    function clamp01(value) {
230	      return Math.max(0, Math.min(1, value));
231	    }
232	
233	    function smoothSegment(start, end, value) {
234	      const progress = clamp01((value - start) / (end - start));
235	      return progress * progress * (3 - 2 * progress);
236	    }
237	
238	    function easeOutCubic(value) {
239	      const progress = clamp01(value);
240	      return 1 - Math.pow(1 - progress, 3);
241	    }
