243	    function contentOpacity(mode) {
244	      if (visualSourceMode === visualTargetMode)
245	        return mode === visualTargetMode ? 1 : 0;
246	      let opacity = 0;
247	      if (mode === visualSourceMode)
248	        opacity = 1 - smoothSegment(0, 0.48, transitionProgress);
249	      if (mode === visualTargetMode)
