257	        return 0;
258	      if (mode === visualSourceMode) {
259	        const exitProgress = easeOutCubic(transitionProgress / 0.58);
260	        return transitionDirection * 8 * exitProgress;
261	      }
262	      if (mode === visualTargetMode) {
263	        const entryProgress = easeOutCubic(
264	          (transitionProgress - 0.14) / 0.86);
265	        return -transitionDirection * 10 * (1 - entryProgress);
266	      }
267	      return 0;
268	    }
