  90	  readonly property var wiredDevice: Networking.devices.values.find(device =>
  91	    device.type === DeviceType.Wired && device.connected) ?? null
  92	  readonly property var wifiNetworks: {
  93	    if (wifiDevice === null)
  94	      return [];
  95	    const networks = wifiDevice.networks.values.map(network => ({
  96	      "ssid": network.name,
  97	      "strength": Math.round(network.signalStrength * 100),
  98	      "security": WifiSecurityType.toString(network.security),
  99	      "active": network.connected,
 100	      "known": network.known,
 101	      "nativeNetwork": network
 102	    }));
 103	    networks.sort((left, right) => {
 104	      if (left.active !== right.active)
 105	        return left.active ? -1 : 1;
 106	      if (left.strength !== right.strength)
 107	        return right.strength - left.strength;
 108	      return left.ssid.localeCompare(right.ssid);
 109	    });
