 314	  function appFuzzyScore(candidate, query) {
 315	    const name = candidate.normalizedName;
 316	    const text = candidate.searchText;
 317	    if (name === query)
 318	      return 10000;
 319	
 320	    let score = name.startsWith(query) ? 1200
 321	      : name.includes(query) ? 700 : 0;
 322	    let previous = -1;
 323	    let streak = 0;
 324	    let gaps = 0;
 325	
 326	    for (let index = 0; index < query.length; ++index) {
 327	      const position = text.indexOf(query[index], previous + 1);
 328	      if (position < 0)
 329	        return -1;
 330	      const gap = previous < 0 ? position : position - previous - 1;
 331	      gaps += gap;
 332	      streak = gap === 0 ? streak + 1 : 0;
 333	      score += 20 + streak * 14;
 334	      if (position === 0 || " -_./".includes(text[position - 1]))
 335	        score += 45;
 336	      previous = position;
 337	    }
 338	
 339	    score -= gaps * 3;
 340	    score -= Math.max(0, name.length - query.length) * 0.2;
 341	    return score;
 342	  }
